use constant {
    PLUGIN_DIR          => './plugins',
    MAX_PLUGIN_SIZE     => 10_240,        # 10 KB max plugin size
    PLUGIN_TIMEOUT_SECS => 5,
    APPROVED_HASHES_FILE => './approved_plugin_hashes.txt',
};

# Patterns that are forbidden in plugin code
my @FORBIDDEN_PATTERNS = (
    qr/\bsystem\s*\(/,
    qr/\bexec\s*\(/,
    qr/\b`[^`]*`/,                    # backticks
    qr/\bqx\s*[\(\{\/\|]/,           # qx operator
    qr/\bopen\s*\(\s*\$?\w+\s*,\s*["']?\s*[\|>]/,  # open with pipe/write
    qr/\bunlink\s*\(/,
    qr/\brmdir\s*\(/,
    qr/\brename\s*\(/,
    qr/\bchmod\s*\(/,
    qr/\bchown\s*\(/,
    qr/\bkill\s*\(/,
    qr/\bfork\s*\(/,
    qr/\brequire\s+/,
    qr/\buse\s+/,
    qr/\bdo\s+["']/,
    qr/\beval\s*\(/,                  # no nested eval
    qr/\bBEGIN\s*\{/,
    qr/\bINIT\s*\{/,
    qr/\bENV\s*\{/,
    qr/\b\$ENV\b/,
    qr/\bFile::|\bIO::|\bSocket/,
    qr/\bDBI\b/,
    qr/\bLWP\b|\bHTTP::/,
);

# Load approved plugin hashes from file
sub load_approved_hashes {
    my %approved;
    if (-f APPROVED_HASHES_FILE) {
        open my $fh, '<', APPROVED_HASHES_FILE
            or do { warn "Cannot read approved hashes file: $!\n"; return %approved; };
        while (my $line = <$fh>) {
            chomp $line;
            $line =~ s/#.*//;         # strip comments
            $line =~ s/^\s+|\s+$//g;  # trim
            next unless $line;
            $approved{$line} = 1;
        }
        close $fh;
    }
    return %approved;
}

# Validate plugin code against forbidden patterns
sub validate_plugin_code {
    my ($code, $plugin_name) = @_;
    my @violations;

    for my $pattern (@FORBIDDEN_PATTERNS) {
        if ($code =~ $pattern) {
            push @violations, "Forbidden pattern detected: $pattern";
        }
    }

    if (@violations) {
        return (0, "Plugin '$plugin_name' failed security validation:\n  " . join("\n  ", @violations));
    }
    return (1, "OK");
}

# Safely read a plugin file with path traversal protection
sub read_plugin_file {
    my ($plugin_name) = @_;

    # Sanitize plugin name: allow only alphanumeric, underscore, hyphen
    unless ($plugin_name =~ /\A[a-zA-Z0-9_-]+\z/) {
        return (undef, "Invalid plugin name: '$plugin_name'. Only alphanumeric, underscore, and hyphen allowed.");
    }

    my $plugin_path = PLUGIN_DIR . "/$plugin_name.pl";

    # Resolve to absolute and verify it's within PLUGIN_DIR
    use Cwd qw(abs_path);
    my $abs_plugin_dir = abs_path(PLUGIN_DIR);
    unless (defined $abs_plugin_dir && -d $abs_plugin_dir) {
        return (undef, "Plugin directory does not exist: " . PLUGIN_DIR);
    }

    unless (-f $plugin_path) {
        return (undef, "Plugin file not found: $plugin_path");
    }

    my $abs_plugin_path = abs_path($plugin_path);
    unless (defined $abs_plugin_path && index($abs_plugin_path, $abs_plugin_dir) == 0) {
        return (undef, "Path traversal detected for plugin '$plugin_name'.");
    }

    # Check file size
    my $size = -s $plugin_path;
    if ($size > MAX_PLUGIN_SIZE) {
        return (undef, "Plugin '$plugin_name' exceeds maximum allowed size (" . MAX_PLUGIN_SIZE . " bytes).");
    }

    open my $fh, '<', $plugin_path
        or return (undef, "Cannot open plugin file '$plugin_path': $!");
    local $/;
    my $code = <$fh>;
    close $fh;

    return ($code, undef);
}

# Execute plugin code in a sandboxed namespace with timeout
sub execute_plugin {
    my ($plugin_name, %params) = @_;

    print "=" x 60, "\n";
    print "Loading plugin: $plugin_name\n";

    # Step 1: Read the plugin file
    my ($code, $read_err) = read_plugin_file($plugin_name);
    if ($read_err) {
        warn "ERROR: $read_err\n";
        return { success => 0, error => $read_err };
    }

    print "  [OK] File read successfully (" . length($code) . " bytes)\n";

    # Step 2: Verify code hash against approved list
    my %approved_hashes = load_approved_hashes();
    my $code_hash = sha256_hex($code);
    print "  Plugin SHA-256: $code_hash\n";

    if (%approved_hashes && !$approved_hashes{$code_hash}) {
        my $msg = "Plugin '$plugin_name' hash not in approved list. "
                . "Add this hash to " . APPROVED_HASHES_FILE . " to approve it:\n"
                . "  $code_hash";
        warn "SECURITY: $msg\n";
        return { success => 0, error => $msg };
    }
    print "  [OK] Hash verified against approved list\n";

    # Step 3: Static analysis - check for forbidden patterns
    my ($valid, $validation_msg) = validate_plugin_code($code, $plugin_name);
    unless ($valid) {
        warn "SECURITY: $validation_msg\n";
        return { success => 0, error => $validation_msg };
    }
    print "  [OK] Static security analysis passed\n";

    # Step 4: Wrap code in sandboxed namespace
    my $namespace = "PluginSandbox::${plugin_name}";
    my $wrapped_code = qq{
        package $namespace;
        use strict;
        use warnings;
        no strict 'refs';

        # Make params available to plugin
        our \%PARAMS = \%params;
        our \%RESULT = ();

        # Execute plugin code
        $code

        # Return results
        return \\\%RESULT;
    };

    # Step 5: Execute with timeout
    print "  Executing plugin with " . PLUGIN_TIMEOUT_SECS . "s timeout...\n";

    my $result;
    my $eval_error;

    eval {
        local $SIG{ALRM} = sub { die "Plugin execution timed out after " . PLUGIN_TIMEOUT_SECS . " seconds\n" };
        alarm(PLUGIN_TIMEOUT_SECS);

        # Execute in restricted context
        $result = eval $wrapped_code;
        $eval_error = $@;

        alarm(0);
    };

    my $outer_error = $@;
    alarm(0);  # Ensure alarm is cleared

    if ($outer_error) {
        warn "ERROR: Plugin '$plugin_name' - $outer_error\n";
        return { success => 0, error => $outer_error };
    }

    if ($eval_error) {
        warn "ERROR: Plugin '$plugin_name' execution failed: $eval_error\n";
        return { success => 0, error => $eval_error };
    }

    print "  [OK] Plugin executed successfully\n";

    # Clean up the namespace
    {
        no strict 'refs';
        my $stash = \%{"${namespace}::"};
        delete @{$stash}{keys %$stash};
    }

    return { success => 1, result => $result };
}

